	@Test
	void minusAntiExistsAlternativePushesToSmallestAssuredPrefix() {
		TupleExpr codePrefix = new Join(values("code", VF.createIRI("urn:med:1000")),
				pattern("med", "codePredicate", "code"));
		TupleExpr left = new Join(codePrefix, pattern("med", "typePredicate", "type"));
		Filter rhs = new Filter(pattern("med", "dosagePredicate", "dose"), containsLowercaseDoseX());
		rhs.setVariableScopeChange(true);
		Difference difference = new Difference(left, rhs);

		CompiledRule pushedRule = RuleCompiler.compile(StandardRuleSpecs.minusAntiExistsPushedAlternative());
		assertTrue(pushedRule.matches(expr(difference), null, null), () -> pushedRule.trace(expr(difference), null)
				.toString());

		List<RuleApplication> applications = RuleCompiler.compileAll(StandardRuleSpecs.logicalRules())
				.stream()
				.flatMap(rule -> rule.apply(expr(difference), null, null).stream())
				.toList();

		assertTrue(applications.stream().anyMatch(StandardRuleSpecTest::isAntiExistsBeforeTypeSuffix),
				"MINUS should produce an alternative that evaluates FILTER NOT EXISTS after the selective code "
						+ "prefix and before the broad type suffix. Alternatives:\n" + applications.stream()
								.map(application -> application.metadata() + "\n" + application.alternative())
								.collect(Collectors.joining("\n---\n")));
	}

	@Test
	void minusAntiExistsAlternativePushesBelowExistingExistsFilter() {
		TupleExpr codePrefix = new Join(values("code", VF.createIRI("urn:med:1000")),
				pattern("med", "codePredicate", "code"));
		TupleExpr typedCodePrefix = new Join(codePrefix, pattern("med", "typePredicate", "type"));
		TupleExpr left = new Filter(typedCodePrefix, new Exists(pattern("patient", "hasMedicationPredicate", "med")));
		Filter rhs = new Filter(pattern("med", "dosagePredicate", "dose"), containsLowercaseDoseX());
		rhs.setVariableScopeChange(true);
		Difference difference = new Difference(left, rhs);

		CompiledRule pushedRule = RuleCompiler.compile(StandardRuleSpecs.minusAntiExistsPushedAlternative());
		assertTrue(pushedRule.matches(expr(difference), null, null), () -> pushedRule.trace(expr(difference), null)
				.toString());

		List<RuleApplication> applications = RuleCompiler.compileAll(StandardRuleSpecs.logicalRules())
				.stream()
				.flatMap(rule -> rule.apply(expr(difference), null, null).stream())
				.toList();

		assertTrue(applications.stream().anyMatch(StandardRuleSpecTest::isAntiExistsBelowOuterExistsFilter),
				"MINUS should produce an alternative that evaluates FILTER NOT EXISTS after VALUES+code, before "
						+ "type, and below the existing patient EXISTS filter. Alternatives:\n"
						+ applications.stream()
								.map(application -> application.metadata() + "\n" + application.alternative())
								.collect(Collectors.joining("\n---\n")));
	}

