	private static MemoExpr expr(TupleExpr tupleExpr) {
		return expr(tupleExpr, RuleKind.TRANSFORMATION, PhysicalProperties.ANY);
	}

	private static MemoExpr expr(TupleExpr tupleExpr, RuleKind kind, PhysicalProperties deliveredProperties) {
		return new MemoExpr(0, 0, tupleExpr.getClass().getSimpleName(), List.of(), "", tupleExpr,
				deliveredProperties, kind, CostVector.ZERO, List.of(), null, null);
	}

	private static StatementPattern pattern(String subject, String predicate, String object) {
		return new StatementPattern(new Var(subject), new Var(predicate), new Var(object));
	}

	private static ListMemberOperator listMember(String variableName, IRI... values) {
		ListMemberOperator operator = new ListMemberOperator();
		operator.addArgument(new Var(variableName));
		for (IRI value : values) {
			operator.addArgument(new ValueConstant(value));
		}
		return operator;
	}

	private static ProjectionElemList projectionList(String... names) {
		ProjectionElemList list = new ProjectionElemList();
		for (String name : names) {
			list.addElement(new ProjectionElem(name));
		}
		return list;
	}

	private static BindingSetAssignment values(String name, IRI... values) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingNames(new LinkedHashSet<>(Set.of(name)));
		List<BindingSet> rows = new ArrayList<>();
		for (IRI value : values) {
			MapBindingSet row = new MapBindingSet(1);
			row.addBinding(name, value);
			rows.add(row);
		}
		assignment.setBindingSets(rows);
		return assignment;
	}

	private static ValueExpr containsLowercaseDoseX() {
		return new FunctionCall(FN.CONTAINS.stringValue(),
				new FunctionCall(FN.LOWER_CASE.stringValue(), new Str(new Var("dose"))),
				new ValueConstant(VF.createLiteral("x")));
	}

	private static int countRows(BindingSetAssignment assignment) {
		int rows = 0;
		for (BindingSet ignored : assignment.getBindingSets()) {
			rows++;
		}
		return rows;
	}

	private static boolean isAntiExistsBeforeTypeSuffix(RuleApplication application) {
		if (!(application.alternative()instanceof Join join)
				|| !(join.getLeftArg()instanceof Filter filter)
				|| !(filter.getCondition()instanceof Not not)
				|| !(not.getArg() instanceof Exists)) {
			return false;
		}
		return containsPredicateVar(filter.getArg(), "codePredicate")
				&& !containsPredicateVar(filter.getArg(), "typePredicate")
				&& containsPredicateVar(join.getRightArg(), "typePredicate");
	}

	private static boolean isAntiExistsBelowOuterExistsFilter(RuleApplication application) {
		if (!(application.alternative()instanceof Filter outerFilter)
				|| !(outerFilter.getCondition() instanceof Exists)
				|| !(outerFilter.getArg()instanceof Join join)
				|| !(join.getLeftArg()instanceof Filter antiFilter)
				|| !(antiFilter.getCondition()instanceof Not not)
				|| !(not.getArg() instanceof Exists)) {
			return false;
		}
		return containsPredicateVar(antiFilter.getArg(), "codePredicate")
				&& !containsPredicateVar(antiFilter.getArg(), "typePredicate")
				&& containsPredicateVar(join.getRightArg(), "typePredicate");
	}

	private static boolean containsPredicateVar(TupleExpr tupleExpr, String predicateName) {
		if (tupleExpr instanceof StatementPattern pattern) {
			return pattern.getPredicateVar() != null && predicateName.equals(pattern.getPredicateVar().getName());
		}
		if (tupleExpr instanceof Join join) {
			return containsPredicateVar(join.getLeftArg(), predicateName)
					|| containsPredicateVar(join.getRightArg(), predicateName);
		}
		if (tupleExpr instanceof Filter filter) {
			return containsPredicateVar(filter.getArg(), predicateName);
		}
		return false;
	}

	private static boolean containsCompiledRule(List<CascadesRule> rules, String id) {
		return rules.stream().anyMatch(rule -> rule instanceof CompiledRule && id.equals(rule.id()));
	}
